import type { HTMLAttributes, ReactElement } from 'react';
import type { TabProps } from './Tab/';
/**
 * конструкция с Omit говорит использовать все пропсы div, за испоключением перечисленных справа
 * т.к они будут в пропсах компонента
 */
type Falsy = undefined | null | boolean;
export interface TabsProps extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange'> {
    /** Class name of base container. */
    className?: string;
    /**
     * вызывается при изменении текущего таба внутри компонента (например при клике пользователя)
     *
     * @param currentTabIndex значение пропса index, выбранного таба
     */
    onChange?: (currentTabIndex: number) => void;
    /**
     * индекс выбранного таба, нужен для програмного управления текущим табом
     */
    selectedTabIndex?: number;
    /**
     * вложенные компоненты Tab
     */
    children: Array<ReactElement<TabProps> | Falsy> | ReactElement<TabsProps | Falsy>;
    /**
     * Пропс из устаревшей реализации табов,
     * нужен для мягкого перехода, чтобы линтер пользователя не ругался на несуществующий пропс
     * @deprecated
     */
    align?: 'left' | 'center' | 'right';
    /**
     * Пропс из устаревшей реализации табов,
     * нужен для мягкого перехода, чтобы линтер пользователя не ругался на несуществующий пропс
     * @deprecated
     */
    divider?: boolean;
    /**
     * Пропс для общего класса для body
     */
    bodyClassName?: string;
}
export {};
